/**
 * Form — printable form fields for React PDF documents.
 *
 * @registryTitle PDF Form
 * @registryDescription Printable text and checkbox fields for generated PDF forms.
 * @registryCategory forms
 * @registryDemos basic=Basic, checkbox=Checkbox
 */

import * as React from "react";
import { View, Text, StyleSheet } from "@react-pdf/renderer";
import type { Style } from "@react-pdf/types";
import {
  mergePdfStyles,
  type PdfStyleInput,
  usePdfTheme,
} from "@/lib/pdf-theme";

export interface PdfFormProps {
  children: React.ReactNode;
  columns?: 1 | 2;
  style?: PdfStyleInput;
}

export interface PdfFormFieldProps {
  label: string;
  value?: React.ReactNode;
  placeholder?: string;
  lines?: number;
  style?: PdfStyleInput;
}

export interface PdfCheckboxFieldProps {
  label: string;
  checked?: boolean;
  style?: PdfStyleInput;
}

export function PdfForm({ children, columns = 1, style }: PdfFormProps) {
  const styles = StyleSheet.create({
    root: {
      flexDirection: columns === 2 ? "row" : "column",
      gap: 8,
      flexWrap: "wrap",
    } as Style,
  });
  return <View style={mergePdfStyles(styles.root, style)}>{children}</View>;
}

export function PdfFormField({
  label,
  value,
  placeholder = "",
  lines = 1,
  style,
}: PdfFormFieldProps) {
  const theme = usePdfTheme();
  const styles = StyleSheet.create({
    field: { flex: 1, marginBottom: theme.spacing.sm } as Style,
    label: {
      color: theme.colors.mutedForeground,
      fontFamily: theme.typography.fontFamily,
      fontSize: theme.typography.xs,
      marginBottom: 4,
      textTransform: "uppercase",
    } as Style,
    box: {
      borderColor: theme.colors.border,
      borderRadius: theme.radii.sm,
      borderWidth: 1,
      minHeight: lines * 18,
      padding: 6,
    } as Style,
    value: {
      color: value ? theme.colors.foreground : theme.colors.mutedForeground,
      fontFamily: theme.typography.fontFamily,
      fontSize: theme.typography.sm,
    } as Style,
  });
  return (
    <View style={mergePdfStyles(styles.field, style)}>
      <Text style={styles.label}>{label}</Text>
      <View style={styles.box}>
        <Text style={styles.value}>{value ?? placeholder}</Text>
      </View>
    </View>
  );
}

export function PdfCheckboxField({
  label,
  checked = false,
  style,
}: PdfCheckboxFieldProps) {
  const theme = usePdfTheme();
  const styles = StyleSheet.create({
    row: {
      alignItems: "center",
      flexDirection: "row",
      gap: 6,
      marginBottom: theme.spacing.sm,
    } as Style,
    box: {
      alignItems: "center",
      borderColor: theme.colors.border,
      borderWidth: 1,
      height: 10,
      justifyContent: "center",
      width: 10,
    } as Style,
    check: { color: theme.colors.primary, fontSize: 8 } as Style,
    label: {
      color: theme.colors.foreground,
      fontFamily: theme.typography.fontFamily,
      fontSize: theme.typography.sm,
    } as Style,
  });
  return (
    <View style={mergePdfStyles(styles.row, style)}>
      <View style={styles.box}>
        {checked ? <Text style={styles.check}>✓</Text> : null}
      </View>
      <Text style={styles.label}>{label}</Text>
    </View>
  );
}

/**
 * PDF Theme — shared theme tokens and helpers for edbn/ui PDF components.
 *
 * @registryTitle PDF Theme
 * @registryDescription Theme provider, default tokens, and style helpers for PDF components.
 * @registryVariant pdf
 * @registryType registry:lib
 */

import * as React from "react";
import type { Style } from "@react-pdf/types";

// ---- TYPES -----------------------------------------------------------------

export interface PdfTheme {
  colors: {
    background: string;
    foreground: string;
    mutedForeground: string;
    border: string;
    primary: string;
    primaryForeground: string;
    muted: string;
    destructive: string;
    warning: string;
    success: string;
  };
  spacing: {
    page: number;
    section: number;
    gap: number;
    sm: number;
    md: number;
    lg: number;
  };
  radii: {
    sm: number;
    md: number;
    lg: number;
  };
  typography: {
    fontFamily: string;
    monoFontFamily: string;
    xs: number;
    sm: number;
    base: number;
    lg: number;
    xl: number;
    xxl: number;
  };
}

export type PdfStyleInput = Style | Style[] | null | undefined | false;

// ---- DEFAULT THEME ---------------------------------------------------------

export const defaultPdfTheme: PdfTheme = {
  colors: {
    background: "#ffffff",
    foreground: "#111827",
    mutedForeground: "#6b7280",
    border: "#d1d5db",
    primary: "#2563eb",
    primaryForeground: "#ffffff",
    muted: "#f3f4f6",
    destructive: "#dc2626",
    warning: "#b45309",
    success: "#15803d",
  },
  spacing: {
    page: 36,
    section: 16,
    gap: 10,
    sm: 6,
    md: 10,
    lg: 16,
  },
  radii: {
    sm: 4,
    md: 7,
    lg: 10,
  },
  typography: {
    fontFamily: "Helvetica",
    monoFontFamily: "Courier",
    xs: 8,
    sm: 9,
    base: 10.5,
    lg: 13,
    xl: 18,
    xxl: 28,
  },
};

// ---- CONTEXT ---------------------------------------------------------------

const PdfThemeContext = React.createContext<PdfTheme>(defaultPdfTheme);

export interface PdfThemeProviderProps {
  theme?: Partial<PdfTheme>;
  children: React.ReactNode;
}

function mergeTheme(theme?: Partial<PdfTheme>): PdfTheme {
  if (!theme) return defaultPdfTheme;
  return {
    colors: { ...defaultPdfTheme.colors, ...theme.colors },
    spacing: { ...defaultPdfTheme.spacing, ...theme.spacing },
    radii: { ...defaultPdfTheme.radii, ...theme.radii },
    typography: { ...defaultPdfTheme.typography, ...theme.typography },
  };
}

export function PdfThemeProvider({ theme, children }: PdfThemeProviderProps) {
  const resolvedTheme = React.useMemo(() => mergeTheme(theme), [theme]);
  return (
    <PdfThemeContext.Provider value={resolvedTheme}>
      {children}
    </PdfThemeContext.Provider>
  );
}

export function usePdfTheme(): PdfTheme {
  return React.useContext(PdfThemeContext) ?? defaultPdfTheme;
}

// ---- STYLE HELPERS ---------------------------------------------------------

export function mergePdfStyles(...styles: PdfStyleInput[]): Style[] {
  return styles.flatMap((style) => {
    if (!style) return [];
    return Array.isArray(style) ? style.filter(Boolean) : [style];
  });
}

export function getToneColor(theme: PdfTheme, tone?: string): string {
  switch (tone) {
    case "primary":
      return theme.colors.primary;
    case "muted":
      return theme.colors.mutedForeground;
    case "destructive":
      return theme.colors.destructive;
    case "warning":
      return theme.colors.warning;
    case "success":
      return theme.colors.success;
    default:
      return theme.colors.foreground;
  }
}
